var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>먼 옛날, 사람들의 두려움을 사는 큰 뱀이 있었다.</color>","JPN":"<color=#ffd34c>遥か昔、人々から恐れられた大蛇がいた。</color>","ENG":"<color=#ffd34c>A long time ago, there was a giant snake that everyone feared.</color>","TWN":"<color=#ffd34c>很久很久以前，有條令人害怕的大蛇。</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>하지만 바람의 목소리를 들을 줄 아는 여인이 큰 뱀의 외로운 마음을 달래어, 수호신으로 모셨다.</color>","JPN":"<color=#ffd34c>しかし、風の声を聞くことができるとある女が\\n大蛇の寂しさを癒し、守護神として崇めた。</color>","ENG":"<color=#ffd34c>But a woman who could hear the voice of wind soothed the snake, and worshipped it as a guardian god.</color>","TWN":"<color=#ffd34c>但是聽得懂風聲的女人，安慰大蛇孤獨的心情後，將其奉爲守護神。</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>뱀은 보답으로 여인을 무녀로 삼고 영생을 선물했다. 피부는 혈색을 잃지 않고 병드는 일이 없었다.</color>","JPN":"<color=#ffd34c>蛇は恩返しとして、女を巫女にして永遠の命を与えた。\\n肌は血色を失わず、病気にかかることもなかった。</color>","ENG":"<color=#ffd34c>The snake made the woman its priestess, and gave her eternal life. The priestess never withered nor sickened.</color>","TWN":"<color=#ffd34c>大蛇將女人視為巫女，並將永生送給她當作回報。巫女的膚色永遠那樣紅潤，也從不生病。</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>무녀를 부러워하던 사람들은 문득 생각했다.</color>","JPN":"<color=#ffd34c>巫女を羨ましがっていた人々はふと思った。</color>","ENG":"<color=#ffd34c>Those who were jealous of the priestess came up with an idea:</color>","TWN":"<color=#ffd34c>羨慕巫女的人們突然想到。</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>뱀의 힘이 깃든 무녀의 피를 마시면, 우리도 영생을 누릴 수 있지 않을까?</color>","JPN":"<color=#ffd34c>蛇の力が宿った巫女の血を飲めば、\\n私たちも永遠の命を手にすることができるのでは？</color>","ENG":"<color=#ffd34c>If we drink the blood of the priestess, we might live forever, too.</color>","TWN":"<color=#ffd34c>若是巫女的血液中有大蛇的法力，那喝下巫女的血後，我們豈不是也能得到永生嗎？</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L9_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"회동은 원래 당주들이 전부 모여야 하는 거 아닌가? 생각보다 너무 적은데?","JPN":"会合は本来なら当主が全員集まらなければならないんだろ？\\n思っていたより人数が少なすぎるようだが。","ENG":"I thought all family leaders were supposed to be here. How come there are so few?","TWN":"不是所有堂主都要參加聚會嗎？人怎麼這麼少？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"다른 당주 분들은 각자 병력을 동원해 봉인역을 지키고 있습니다.","JPN":"他の当主の皆様は各家の兵力を動員して封印域を守っています。","ENG":"Other family leaders are with their own troops, protecting each Seal Domain.","TWN":"其他堂主正在各自動員兵力守護封印域。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"독기에 잠식된 침식체들이 오로치의 봉인을 파괴하려 들고 있으니 말이지요.","JPN":"毒に侵された侵食体たちが、オロチの封印を破壊しようとしているからです。","ENG":"Even now, poisoned C.O.s are attacking the Seal Domains to free Orochi.","TWN":"因為有消息說，被毒氣侵蝕的侵蝕體正試圖破壞大蛇的封印。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"저기, 질문 하나 해도 괜찮을까요?","JPN":"あの、一つ質問してもいいですか？","ENG":"Do you mind if I ask you a question?","TWN":"請問我可以問一個問題嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"오로치가 정확히 뭐죠? 신화에 등장하는 괴물인가요?","JPN":"オロチとは何ですか？　神話に登場する化け物ですか？","ENG":"What is Orochi? Isn’t that the monster from a myth?","TWN":"大蛇是什麼？是神話中的怪物嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"오로치라면…….","JPN":"オロチは……","ENG":"Orochi is...","TWN":"大蛇是……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"흥. 연합에 얼씬거리지도 않던 방계 집안 자식답게 아무것도 모르는군.","JPN":"ふん。連合に顔すら出さなかった傍系の息子らしく、何も知らないようだな。","ENG":"Hah, you know nothing. But what can we expect from the collateral family that has been ignoring the Alliance for years?","TWN":"哼，果然是都沒在跟聯盟來往的旁系，什麼都不知道！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"사요 님, 저 애송이 말 들으셨지요. 나유카 가문은 진즉 맥이 끊긴 겁니다.","JPN":"小夜様、あの小僧の言葉を聞かれましたね。\\n奈由香家はもう家系が絶たれたと考えてよいでしょう。","ENG":"Elder Sayo, you heard the boy. The Nayuka family is already lost to us.","TWN":"小夜，你有聽到那個小鬼說的話吧？南裕夏家族早就後繼無人啦！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"외부인이나 다름없는데 뭘 기대하겠습니까. 어서 내보내시죠.","JPN":"部外者同然な者に何も期待できませぬ。\\n早くここから出ていってもらいましょう。","ENG":"They are just outsiders. Send this boy away.","TWN":"根本和外人沒什麼兩樣，還要期待什麼？快讓他離開吧！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"뭐라고?! 이 영감이 진짜!","JPN":"はあ！？　何言ってんだジジイ！","ENG":"What did you just say?","TWN":"你說什麼？！臭老頭！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"언성을 낮추세요. 마사키.","JPN":"大声は控えてください、雅紀様。","ENG":"Watch your tone, Masaki.","TWN":"請降低音量，雅紀。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"신화 속의 오로치와 같은 존재라고 볼 수 있겠지만, 가문 연합에서 전해져 내려오는 내력은 알려진 것과 다릅니다.","JPN":"神話のオロチのような存在とみることもできるでしょうが、\\n連合の伝承は知られているものとは異なります。","ENG":"This may be the Orochi from the myth, but the truth we know about this creature is different from the lore.","TWN":"雖然可以視作是神話中的大蛇，但是和家族聯盟流傳下來的傳統是不一樣的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"오로치는 한때 인간을 지켜 주던 불사의 수호신이었습니다.","JPN":"オロチはかつて、人間を守っていた不死の守護神でした。","ENG":"Orochi once was an immortal guardian god that protected humans.","TWN":"大蛇曾經是守護人類的守護神。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"하지만 인간을 누구보다 증오하는 괴물이 되는 바람에, 나나하라 가문의 초대 당주께서 봉인하셨죠.","JPN":"しかし、人間を誰よりも憎む怪物となってしまったため、\\n七原家の初代ご当主が封印されました。","ENG":"But later, it turned into a monster that hated humans. That’s why the first leader of the Nanahara family sealed the creature away.","TWN":"後來變成憎恨人類的怪物，於是七原家族的初代堂主將其封印起來。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"저희는 그 후 선조의 업을 계승해 오로치를 잠재운 봉인을 지켜 온 것입니다.","JPN":"その後私たちは先祖の業を継承し、オロチを眠らせている封印を守ってきたのです。","ENG":"Then the descendants followed their ancestors’ will, protecting the seals of Orochi.","TWN":"此後，我們便繼承祖先的使命，一直守護著鎮壓大蛇的封印。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아직 잠들어 있을 뿐인데…… 도시를 이렇게 만들었다고요?","JPN":"まだ眠っているのに……都市をあんな風にできるんですか？","ENG":"Orochi is still asleep... yet it can affect the entire city?","TWN":"還沒甦醒過來……就已經把城市弄成這副模樣？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네. 지금은 새어나온 독기에 불과하지만, 오로치의 힘의 근간은 재해입니다.","JPN":"はい。今は毒が漏れた程度に過ぎませんが、\\nオロチの力の根幹は災害です。","ENG":"Yes. It’s due to the poison that leaked from the seal; Orochi’s power is based on disasters.","TWN":"是的。雖然現在只有釋出毒氣，但大蛇力量的根源是災害。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"태풍과 해일, 그리고 지진. 하늘과 땅과 바다를 휘감고 뒤흔드는 괴물이죠.","JPN":"台風と津波、そして地震。\\n空と地と海を包み込んで揺るがす化け物です。","ENG":"It calls for storms, tsunamis, and earthquakes. It’s the monster that shakes the sky and the earth.","TWN":"颱風和海嘯，還有地震。她是可以撼動天、地、海的怪物。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"오로치의 봉인이 약해졌으니 맞서 싸울 채비를 갖춰야 합니다.","JPN":"オロチの封印が弱まっている今、我々は対抗する準備を整えなければなりません。","ENG":"The seals on Orochi are weakening. We have to get ready for battle.","TWN":"大蛇的封印力越來越弱，因此要做好對抗的準備。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"이제는 연합의 힘만으로 해결할 수 있는 선을 넘었으니까요.","JPN":"もはや連合の力だけで解決できる域を越えておりますので。","ENG":"We can’t handle the monster just by ourselves.","TWN":"但現在已經不是光靠聯盟的力量就能解決的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"아뇨. 관리국도, 태스크포스도 이 일에 끌어들이면 더 많은 희생을 낼 뿐입니다.","JPN":"いえ、管理局やタスクフォースカンパニーを巻き込んでしまえば、\\nより多くの犠牲を払うだけです。","ENG":"I disagree. Calling the Administration and TASKFORCE companies for help will only result in even more victims.","TWN":"不，把管理局和特遣勢力也拖下水的話，只會造成更多的犧牲。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"초대 당주께서도 이르셨죠. 오로치의 존재가 알려지면 인간의 욕망 때문에 더 큰 화를 부를 것이라고.","JPN":"初代ご当主もおっしゃいました。オロチの存在が世間に知られれば、\\n人間の欲望によってさらに大きな災いを招くだろう、と。","ENG":"Our first family leader also said that even knowing of the existence of Orochi itself will corrupt humans, because of their insatiable desires.","TWN":"初代堂主也有說過。若是人類發現大蛇的存在，恐怕會因爲人類的慾望，而造成更大的禍害。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"흥, 당주께서는 그저 3년 전의 일이 되풀이 될까봐 두려워하시는 것 아닙니까?","JPN":"ふん、ご当主は3年前のことが繰り返されることを恐れておられるだけなのでは？","ENG":"Hah, you’re only afraid that the accident three years ago might happen again.","TWN":"哼，堂主不就是怕三年前的事件重演嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"아, 그러고 보니 나유카의 말예를 데려오신 것도 그 때문이셨군요.","JPN":"あ、そういえば奈由香の末裔を連れてこられたのも、そのためだったのでしょう。","ENG":"But then, I suppose you summoned the distant descendant of Nayuka here for that reason.","TWN":"哦～這麼說來，堂主把南裕夏的後裔找來也是因為這樣吧？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"저 어린 것이 혹시라도 전승대로 별을 떨어트리는 기적을 일으킬지도 모르니 말입니다. 허허.","JPN":"もしかしたらあの若造が、伝承どおりに星を落とす奇跡を起こすかもしれませんからな、フォッフォッ。","ENG":"In hopes that the boy might actually work a miracle - shooting a star down, just like in the legend.","TWN":"那個小鬼或許會有家族遺傳，可以創造出讓星星落下的奇蹟呢。 呵呵。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"미나토? 갑자기 어딜 가려는 거냐?","JPN":"湊？　急にどこへ行くんだ？","ENG":"Minato? Where are you going?","TWN":"南裕夏？你是要去哪裡？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그러니까, 오로치를 막아주는 봉인이란 걸 지키고 있다는 거지?","JPN":"つまり、オロチを阻止する封印っていうのを守ってるんだよね？","ENG":"So, they are protecting the seals of Orochi, right?","TWN":"意思就是，要守護鎮壓大蛇的封印是吧？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"여기서 이러고 있는 것보단 나도 그 사람들을 도와야겠어.","JPN":"ここでこんなことしてるよりも、その人たちを助けに行かないと。","ENG":"I’m going to go help them, rather than stay here.","TWN":"那我還待在這裡幹嘛，我應該要去幫那些人吧！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"으음…….","JPN":"ふむ……","ENG":"Mmm...","TWN":"嗯……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"훗. 확실히 저 영감들 말싸움 듣는 건 영양가가 없긴 하지.","JPN":"フッ、確かにあのジジイたちの口喧嘩を聞いたところで、\\n何の役にも立たないからな。","ENG":"Hah hah. True, I don’t see any point in listening to these oldies bickering.","TWN":"呵呵，聽那些老頭在那邊吵架確實是浪費時間。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"예의 없는 것들! 회동 도중에 멋대로 일어나다니!","JPN":"無礼者！　会合中に勝手に席を立とうとするとは！","ENG":"Such insolence! How dare you interrupt the meeting!","TWN":"沒禮貌的東西！竟然擅自在聚會中起身！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"괜찮습니다. 지금은 무작정 전례에만 따를 수 없는 노릇이니까요.","JPN":"構いません。今は昔からのしきたりにこだわるような状況ではありませんので。","ENG":"It is alright. This is not the time to hold fast to our traditions.","TWN":"沒關係，現在不是盲目遵守規定的時候。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"사, 사요 님!","JPN":"さ、小夜様！","ENG":"E-Elder Sayo!","TWN":"小…小夜！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"봉인역으로 안내해 드리겠습니다, 나유카 님. 이쪽으로 오시죠.","JPN":"奈由香様、封印域にご案内します。どうぞこちらへ。","ENG":"Let me show you the way to the Seal Domain. Please follow me, Sir Minato Nayuka.","TWN":"我帶你到封印域，南裕夏，這邊請。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>장로님. 말씀하신 대로 제7 봉인역으로 향하는 호송헬기가 도착했습니다.</color>","JPN":"<color=#ffd34c>長老、ご指示どおり第七封印域に向かう護送ヘリコプターが到着しました。</color>","ENG":"<color=#ffd34c>Elder, the chopper to the 7th Seal Domain is here.</color>","TWN":"<color=#ffd34c>長老，按您的吩咐，飛往第7封印域的護送機已抵達。</color>"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L5_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"봉인역은 지금 위험한 전장입니다.","JPN":"現在、封印域は非常に危険な戦場となっております。","ENG":"The Seal Domain is now at war.","TWN":"封印域現在是非常危險的戰場。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"한 사람이 중한 때라곤 하나, 미나토 공을 보내는 것이 정말 옳은 것인지……. 이 늙은이는 걱정되는군요.","JPN":"人手が欲しい時とはいえ、湊様を送るのが本当に正しいのか……\\nこの老いぼれは心配です。","ENG":"Though any help is welcome, I’m not so sure sending you to the battlefield is the right choice, Sir Minato. I am worried.","TWN":"雖然每一個人力都很寶貴，但是把你送去那裡是正確的嗎……我這個老人家很擔心呢。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"장로인 사요 씨라면, 저희 할아버지를 알고 계시겠네요.","JPN":"長老の小夜さんなら、僕の祖父をご存知でしょうか？","ENG":"I suppose you know my grandfather, Elder Sayo.","TWN":"小夜長老應該認識我爺爺吧？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"네. 당시엔 방계만 살아남은 나유카 가문의 명맥을 이어가던 유일한 분이었지요.","JPN":"はい。当時傍系だけが生き残った奈由香家の血筋を継ぐ、唯一の方でした。","ENG":"Yes. He was the only survivor in the Nayuka family, which was the collateral family.","TWN":"認識，當時他是唯一繼承南裕夏家族命脈的人。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"저 역시 집안의 방계이기에 서로 의지하는 사이였으나…….","JPN":"私も同じく傍系の出身なので、お互いを頼っておりましたが……","ENG":"I am also from the collateral family, so we relied on each other...","TWN":"我也是家族裡的旁系，我們曾經彼此扶持……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"그분은 자손을 얻은 뒤, 가족의 안위를 위해 연합을 떠났습니다.","JPN":"彼は子孫を得た後、家族の安全のために連合を去りました。","ENG":"But when he had a child, he left the Alliance to protect his family.","TWN":"但他獲得子嗣後，爲顧及家人的安危，於是便離開聯盟。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"혹시…… 그것 때문에 저희 할아버지가 원망스러우신가요?","JPN":"もしかして……そのことで僕の祖父は恨まれていますか？","ENG":"Do you... resent my grandfather for that?","TWN":"請問……是因爲這樣而怨恨我爺爺嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"아뇨. 이타심만으로 살아가는 인간은 없습니다.","JPN":"いいえ。利他心だけで生きていく人間はいません。","ENG":"No. One can’t live for others forever.","TWN":"不，沒有人是完全不為自己著想的。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"스스로를 위하려고 하는 것이 인간의 본성이란 걸, 저도 이해하고 있으니까요.","JPN":"自分のために行動するのが人間の本質だということを、私も理解していますから。","ENG":"It is only natural that people seek their own interests.","TWN":"我也明白人類的本性是自私的。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"고맙습니다. 친절하시네요.","JPN":"ありがとうございます。優しいんですね。","ENG":"Thank you. You’re very kind.","TWN":"謝謝你，你真親切。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"카토리 님은 이미 헬기에 오르셨습니다.","JPN":"香取様はすでにヘリコプターに乗りました。","ENG":"Mr. Katori is already in the chopper.","TWN":"香取已經先搭上直升機了。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"……부디, 무사히 돌아오시길 바라죠.","JPN":"……どうか、ご無事で。お帰りをお待ちしております。","ENG":"I wish your safe return.","TWN":"……希望你能夠平安歸來。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};